function calculate({ totalStudents, lowIncomePercentage, spedPercentage, ellPercentage, localPropertyTaxBasePerStudent, localPropertyTaxEffortRate, stateAidFormulaPerStudentBase, programmaticNeedsAdjustment, equitableFundingBenchmarkPerWeightedStudent }) {

  // Input validation and sanitization
  totalStudents = Math.max(0, parseFloat(totalStudents) || 0);
  lowIncomePercentage = Math.min(100, Math.max(0, parseFloat(lowIncomePercentage) || 0));
  spedPercentage = Math.min(100, Math.max(0, parseFloat(spedPercentage) || 0));
  ellPercentage = Math.min(100, Math.max(0, parseFloat(ellPercentage) || 0));
  localPropertyTaxBasePerStudent = Math.max(0, parseFloat(localPropertyTaxBasePerStudent) || 0);
  localPropertyTaxEffortRate = Math.min(100, Math.max(0, parseFloat(localPropertyTaxEffortRate) || 0));
  stateAidFormulaPerStudentBase = Math.max(0, parseFloat(stateAidFormulaPerStudentBase) || 0);
  programmaticNeedsAdjustment = Math.max(0, parseFloat(programmaticNeedsAdjustment) || 0);
  equitableFundingBenchmarkPerWeightedStudent = Math.max(0, parseFloat(equitableFundingBenchmarkPerWeightedStudent) || 0);

  if (totalStudents === 0) {
    return {
      weightedStudentCount: 0,
      equitableFundingTarget: 0,
      localFundingContribution: 0,
      stateFundingContribution: 0,
      programmaticFundingContribution: 0,
      currentFundingCapacity: 0,
      fundingGap: 0,
      fundingGapPerStudent: 0
    };
  }

  // Define weighting factors for additional student needs (research-based averages)
  const lowIncomeFundingWeight = 0.25; // Represents an additional 25% funding for low-income students
  const spedFundingWeight = 1.00;     // Represents an additional 100% funding for SPED students (i.e., twice the base cost)
  const ellFundingWeight = 0.35;      // Represents an additional 35% funding for ELL students

  // 1. Calculate Weighted Student Count
  const numLowIncome = totalStudents * (lowIncomePercentage / 100);
  const numSped = totalStudents * (spedPercentage / 100);
  const numEll = totalStudents * (ellPercentage / 100);

  let weightedStudentCount = totalStudents; // Start with base student count
  weightedStudentCount += numLowIncome * lowIncomeFundingWeight; // Add additional weight for low-income
  weightedStudentCount += numSped * spedFundingWeight;           // Add additional weight for SPED
  weightedStudentCount += numEll * ellFundingWeight;             // Add additional weight for ELL

  // 2. Determine Equitable Funding Target
  const equitableFundingTarget = weightedStudentCount * equitableFundingBenchmarkPerWeightedStudent;

  // 3. Estimate Local Funding Contribution
  const localFundingContribution = totalStudents * localPropertyTaxBasePerStudent * (localPropertyTaxEffortRate / 100);

  // 4. Estimate State Funding Contribution
  const stateFundingContribution = totalStudents * stateAidFormulaPerStudentBase;

  // 5. Estimate Programmatic Funding Contribution
  const programmaticFundingContribution = totalStudents * programmaticNeedsAdjustment;

  // 6. Calculate Total Current Funding Capacity
  const currentFundingCapacity = localFundingContribution + stateFundingContribution + programmaticFundingContribution;

  // 7. Calculate the Funding Gap
  const fundingGap = equitableFundingTarget - currentFundingCapacity;

  // 8. Calculate Funding Gap Per Student
  const fundingGapPerStudent = fundingGap / totalStudents;

  return {
    weightedStudentCount: weightedStudentCount,
    equitableFundingTarget: equitableFundingTarget,
    localFundingContribution: localFundingContribution,
    stateFundingContribution: stateFundingContribution,
    programmaticFundingContribution: programmaticFundingContribution,
    currentFundingCapacity: currentFundingCapacity,
    fundingGap: fundingGap,
    fundingGapPerStudent: fundingGapPerStudent
  };
}
